import h5py
import numpy as np
import torch
from torch.utils.data import Dataset


class MultiAgentPOVDataset(Dataset):

    def __init__(self, h5_path, transform=None):
        """Args:

        h5_path (str): Path to the h5 dataset file.
        transform (callable, optional): Optional transform to be applied
                                        on a sample (e.g., resizing,
                                        normalization).
        """
        self.h5_path = h5_path
        self.transform = transform

        # We keep the file handle as None initially for PyTorch worker safety
        self.file = None

        # Build an index map: global_index -> (episode_key, frame_index, agent_id)
        self.index_map = []

        # Open temporarily just to build the index map
        with h5py.File(self.h5_path, "r") as f:
            for episode_key in f.keys():
                episode_group = f[episode_key]

                # Assuming '0_pov' and '1_pov' have the same length (number of timesteps)
                # Shape is typically (num_frames, height, width, channels)
                num_frames = np.min(episode_group['agents_success_at']).item()#episode_group["0_pov"].shape[0]

                for frame_idx in range(num_frames):
                    # We can treat agent 0 and agent 1 frames as independent samples for VQ-VAE
                    self.index_map.append((episode_key, frame_idx, "0_pov"))
                    self.index_map.append((episode_key, frame_idx, "1_pov"))

    def __len__(self):
        return len(self.index_map)

    def __getitem__(self, idx):
        # Defend against PyTorch Multi-processing issues:
        # H5 files cannot be shared across pickled processes easily.
        # Opening the file lazily on the first __getitem__ call solves this.
        if self.file is None:
            self.file = h5py.File(self.h5_path, "r")

        episode_key, frame_idx, agent_pov_key = self.index_map[idx]

        # Fetch the specific frame (numpy array)
        # Shape: (H, W, C)
        frame = self.file[episode_key][agent_pov_key][frame_idx]

        # VQ-VAEs typically expect PyTorch tensors scaled to [0, 1] or [-1, 1]
        # Convert from HWC to CHW format standard in PyTorch
        # frame = np.transpose(frame, (2, 0, 1))

        # Convert to tensor and scale to [0.0, 1.0] if it's uint8
        # if frame.dtype == np.uint8:
        #     frame = torch.from_numpy(frame).float() / 255.0
        # else:
        #     frame = torch.from_numpy(frame).float()

        # Apply any extra transforms (like normalization or data augmentation)
        if self.transform:
            frame = self.transform(frame)

        return frame

    def close(self):
        """Call this to properly close the h5 file when training is done."""
        if self.file is not None:
            self.file.close()
            self.file = None

    
